package com.google.gson.extras.examples.rawcollections;
import java.util.ArrayList;
import java.util.Collection;

import static org.mockito.Mockito.mockStatic;

import java.io.ByteArrayOutputStream;
import java.io.PrintStream;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import com.google.gson.Gson;
import com.google.gson.JsonArray;
import com.google.gson.JsonParser;

import org.mockito.MockedStatic;

import static org.junit.jupiter.api.Assertions.*;

class RawCollectionsExampleTest {

  private final PrintStream originalOut = System.out;
  private ByteArrayOutputStream outContent;

  private MockedStatic<JsonParser> jsonParserMock;

  @BeforeEach
  void setUp() {
    outContent = new ByteArrayOutputStream();
    System.setOut(new PrintStream(outContent));
  }

  @AfterEach
  void tearDown() {
    System.setOut(originalOut);
    if (jsonParserMock != null) {
      jsonParserMock.close();
    }
  }

  @Test
  void testMain() throws Exception {
    // Use reflection to create Event instance to avoid import error
    Class<?> eventClass = Class.forName("com.google.gson.extras.examples.rawcollections.Event");
    Object eventInstance = eventClass.getConstructor(String.class, String.class)
                                     .newInstance("GREETINGS", "guest");

    // Call the main method
    RawCollectionsExample.main(new String[0]);

    String output = outContent.toString();

    // Check first println output contains expected substring
    assertTrue(output.contains("Using Gson.toJson() on a raw collection: [\"hello\",5,{\"type\":\"GREETINGS\",\"name\":\"guest\"}]"));

    // Check printf output contains expected strings
    assertTrue(output.contains("Using Gson.fromJson() to get: hello, 5, Event(type=GREETINGS, name=guest)") ||
               output.contains("Using Gson.fromJson() to get: hello, 5, com.google.gson.extras.examples.rawcollections.Event@"));

    // We cannot rely on exact toString() of Event, but check partial expected output
  }
}
